      /* <flatten type="Javascript"> */
function setDefault$Voucher$Tax(f) {
  var g = f.getItem("d83")._controlBehavior, z = f.getItem("r30")._controlBehavior, row = 1, u = (f.getItemValue('loai_ct') == '1');
  z._taxAccount = (u ? z._taxCrAccount : z._taxDrAccount), z._taxType = (u ? z._taxCrType : z._taxDrType);
  if (z._rowCount > 1) {
    setDefaultTaxItems(z, z._rowCount, ['ma_tc', 'ma_thue', 'thue_suat', 'tk_thue_no', 'tk_cn', 'ma_mau_ct'], [z._taxProperty, z._taxCode, z._taxRate, z._taxAccount, z._taxType, z._voucherTemplate]);
    return;
  }
  if ((z._rowCount > 0) && (z._getItemValue(row, z._getColumnOrder('so_ct0')) == '')) {
    setDefaultTaxItems(z, row, ['mau_bc', 'ma_tc', 'ma_thue', 'thue_suat', 'tk_thue_no', 'tk_cn', 'ma_mau_ct'],
      ['3', z._taxProperty, z._taxCode, z._taxRate, z._taxAccount, z._taxType, z._voucherTemplate]);
    setDefaultTaxItems(z, row, ['so_ct0', 'so_seri0', 'ngay_ct0', 't_tien_nt', 't_tien', 'ma_kh', 'ten_kh', 'dia_chi', 'ma_so_thue'], f,
      ['so_ct0', 'so_seri0', 'ngay_ct0', 't_tien_nt', 't_tien', 'ma_kh', 'ten_ncc', 'dia_chi', 'ma_so_thue']);
    z.assignExpression(row - 1, z.$a.z_t_thue);
    z.assignExpression(row - 1, z.$a.z_t_thue_nt);
    z.validExpression(null, null, [z.$a.t_thue_nt, z.$a.t_thue], [z.$a.t_tt_nt, z.$a.t_tt]);
    var max = g.max('tien') + 1;
    if (max > 0) z._getItem(1, z._getColumnOrder('ten_vt')).value = g._getItem(max, g._getColumnOrder('ten_vt%l')).value;
  }
}
/* </flatten> */




    &XMLTaxResponse;






declare @ext varchar(6), @type varchar(2), @q nvarchar(4000)
select @type = loai_ct, @ext = convert(char(6), ngay_ct, 112) from m83$000000 where stt_rec = @stt_rec
select top 0 * into #t from r30$000000
select @q = 'insert into #t select * from r30$' + @ext + ' where stt_rec = ''' + replace(@stt_rec, '''', '''''') + ''''
exec sp_executesql @q
if @type = 1 update #t set t_tien_nt = - t_tien_nt, t_tien = - t_tien, t_thue_nt = - t_thue_nt, t_thue = - t_thue
select @@fieldExternal from #t a left join dmtk b on a.tk_thue_no = b.tk where @@whereClause order by @@orderByClause





